/**
 * Analytics models for dashboard reporting.
 */

/**
 * High-level summary of platform analytics.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics data.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

/**
 * Analytics service — aggregates data for dashboard reporting.
 *
 * Depends on:
 * - UserRepository (data layer) for user data
 * - OrderRepository (data layer) for order data
 */

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private userRepository: UserRepository,
    private orderRepository: OrderRepository,
  ) {}

  /**
   * Get a high-level summary of platform analytics.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const users = this.userRepository.findAll();
    const orders = this.orderRepository.findAll();

    const totalUsers = users.length;
    const totalOrders = orders.length;
    const revenue = orders.reduce((sum, order) => sum + order.total, 0);

    // Active users are those who have placed at least one order
    const userIdsWithOrders = new Set(orders.map((order) => order.userId));
    const activeUsers = userIdsWithOrders.size;

    return { totalUsers, totalOrders, revenue, activeUsers };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const orderCount = orders.length;
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    // lastActive is the most recent order date, or user creation date if no orders
    const lastActive = orders.length > 0
      ? orders.reduce((latest, order) =>
          order.createdAt > latest ? order.createdAt : latest, orders[0]!.createdAt)
      : user.createdAt;

    return { userId, orderCount, totalSpent, lastActive };
  }

  /**
   * Get time-series trend data for a metric within a date range.
   *
   * Supported metrics: "orders" and "revenue".
   * Returns one TrendPoint per day in the range.
   */
  getTrends(metric: string, startDate: Date, endDate: Date): TrendPoint[] {
    this.logger.info(`Generating trends for metric: ${metric}`);

    if (metric !== 'orders' && metric !== 'revenue') {
      throw new Error(`Unsupported metric: ${metric}`);
    }

    const orders = this.orderRepository.findAll(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    // Group orders by day
    const dayBuckets = new Map<string, typeof orders>();
    for (const order of orders) {
      const dayKey = order.createdAt.toISOString().slice(0, 10);
      const bucket = dayBuckets.get(dayKey);
      if (bucket) {
        bucket.push(order);
      } else {
        dayBuckets.set(dayKey, [order]);
      }
    }

    // Generate a TrendPoint for each day in the range
    const points: TrendPoint[] = [];
    const current = new Date(startDate);
    while (current <= endDate) {
      const dayKey = current.toISOString().slice(0, 10);
      const dayOrders = dayBuckets.get(dayKey) ?? [];

      const value = metric === 'orders'
        ? dayOrders.length
        : dayOrders.reduce((sum, order) => sum + order.total, 0);

      points.push({
        timestamp: new Date(current),
        metric,
        value,
      });

      current.setDate(current.getDate() + 1);
    }

    return points;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2025-01-01'),
    updatedAt: new Date('2025-01-01'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-0001',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(userRepo, orderRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should aggregate stats from users and orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));
      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-1', total: 30 }));
      orderRepo.save(makeOrder({ id: 'order-3', userId: 'user-2', total: 20 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(2);
      expect(summary.totalOrders).toBe(3);
      expect(summary.revenue).toBe(100);
      expect(summary.activeUsers).toBe(2);
    });

    it('should not count users without orders as active', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));
      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 10 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(2);
      expect(summary.activeUsers).toBe(1);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow('User not found');
    });

    it('should return zero stats for user with no orders', () => {
      userRepo.save(makeUser({ id: 'user-1', createdAt: new Date('2025-03-01') }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toEqual(new Date('2025-03-01'));
    });

    it('should aggregate order data for a user', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      orderRepo.save(makeOrder({
        id: 'order-1',
        userId: 'user-1',
        total: 50,
        createdAt: new Date('2025-02-01'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        userId: 'user-1',
        total: 30,
        createdAt: new Date('2025-03-15'),
      }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(80);
      expect(analytics.lastActive).toEqual(new Date('2025-03-15'));
    });

    it('should not include orders from other users', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));
      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-2', total: 100 }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(1);
      expect(analytics.totalSpent).toBe(50);
    });
  });

  describe('getTrends', () => {
    it('should throw for unsupported metric', () => {
      expect(() =>
        service.getTrends('invalid', new Date('2025-01-01'), new Date('2025-01-03')),
      ).toThrow('Unsupported metric: invalid');
    });

    it('should return daily order counts', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2025-01-01T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2025-01-01T14:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2025-01-03T09:00:00Z') }));

      const points = service.getTrends('orders', new Date('2025-01-01'), new Date('2025-01-03'));

      expect(points).toHaveLength(3);
      expect(points[0]!.metric).toBe('orders');
      expect(points[0]!.value).toBe(2); // Jan 1
      expect(points[1]!.value).toBe(0); // Jan 2
      expect(points[2]!.value).toBe(1); // Jan 3
    });

    it('should return daily revenue', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      orderRepo.save(makeOrder({ id: 'o1', total: 50, createdAt: new Date('2025-01-01T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 30, createdAt: new Date('2025-01-02T10:00:00Z') }));

      const points = service.getTrends('revenue', new Date('2025-01-01'), new Date('2025-01-02'));

      expect(points).toHaveLength(2);
      expect(points[0]!.value).toBe(50);
      expect(points[1]!.value).toBe(30);
    });

    it('should return zeros for days with no orders', () => {
      const points = service.getTrends('orders', new Date('2025-01-01'), new Date('2025-01-03'));

      expect(points).toHaveLength(3);
      expect(points.every((p) => p.value === 0)).toBe(true);
    });

    it('should include correct timestamps on each point', () => {
      const points = service.getTrends('revenue', new Date('2025-06-10'), new Date('2025-06-12'));

      expect(points).toHaveLength(3);
      expect(points[0]!.timestamp).toEqual(new Date('2025-06-10'));
      expect(points[1]!.timestamp).toEqual(new Date('2025-06-11'));
      expect(points[2]!.timestamp).toEqual(new Date('2025-06-12'));
    });
  });
});

